// ══════════════════════════════════════════════
// ANTRIAN / QUEUE
// ══════════════════════════════════════════════
function renderAntrian(el){
  // Auto-reset: clear old queue items
  let queue=DB.get('queue')||[];
  const today=new Date().toDateString();
  queue=queue.filter(q=>new Date(q.createdAt).toDateString()===today || q.status==='waiting' || q.status==='serving');
  DB.set('queue',queue);

  const waiting=queue.filter(q=>q.status==='waiting');
  const serving=queue.filter(q=>q.status==='serving');
  const done=queue.filter(q=>q.status==='done');
  const settings=DB.get('settings')||{queueEstimate:20};
  const est=settings.queueEstimate||20;

  el.innerHTML=`
  <div class="card">
    <div class="card-title">📋 Antrian Hari Ini
      <button class="btn btn-teal btn-sm" onclick="openAddQueue()">+ Walk-in</button>
    </div>
    <div class="grid3" style="margin-bottom:.75rem">
      <div class="stat-card"><div class="stat-val" style="color:var(--gold)">${waiting.length}</div><div class="stat-lbl">Menunggu</div></div>
      <div class="stat-card"><div class="stat-val" style="color:var(--teal)">${serving.length}</div><div class="stat-lbl">Dilayani</div></div>
      <div class="stat-card"><div class="stat-val" style="color:var(--ash)">${done.length}</div><div class="stat-lbl">Selesai</div></div>
    </div>
    ${waiting.length===0&&serving.length===0?'<div class="empty-state"><div class="ei">📋</div><p>Belum ada antrian</p></div>':''}
    ${serving.map(q=>`
    <div style="background:rgba(10,191,188,.08);border:1px solid rgba(10,191,188,.3);border-radius:12px;padding:.75rem;margin-bottom:.5rem">
      <div style="display:flex;justify-content:space-between;align-items:center">
        <div>
          <span style="font-size:1.3rem;font-weight:800;color:var(--teal);margin-right:.5rem">#${q.number}</span>
          <span style="font-weight:700">${q.name}</span>
          <span class="badge badge-teal" style="margin-left:.3rem">Dilayani</span>
        </div>
        <button class="btn btn-sm btn-teal" onclick="queueDone('${q.id}')">✅ Selesai</button>
      </div>
      <div style="font-size:.72rem;color:var(--ash);margin-top:.3rem">✂️ ${q.service} · 🧑 ${q.barber||'-'}</div>
    </div>`).join('')}
    ${waiting.map((q,i)=>`
    <div style="background:var(--s2);border:1px solid var(--b1);border-radius:12px;padding:.75rem;margin-bottom:.5rem">
      <div style="display:flex;justify-content:space-between;align-items:center">
        <div>
          <span style="font-size:1.3rem;font-weight:800;color:var(--gold);margin-right:.5rem">#${q.number}</span>
          <span style="font-weight:700">${q.name}</span>
          <span class="badge badge-gold" style="margin-left:.3rem">Menunggu</span>
          <span style="font-size:.68rem;color:var(--ash);margin-left:.3rem">~${(i+1)*est} mnt</span>
        </div>
        <div style="display:flex;gap:.3rem">
          <button class="btn btn-sm btn-teal" onclick="queueServe('${q.id}')">Mulai</button>
          <button class="btn btn-sm btn-danger" onclick="queueCancel('${q.id}')">Batal</button>
        </div>
      </div>
      <div style="font-size:.72rem;color:var(--ash);margin-top:.3rem">✂️ ${q.service}</div>
    </div>`).join('')}
  </div>
  ${done.length>0?`
  <div class="card">
    <div class="card-title" style="color:var(--ash)">✅ Selesai Hari Ini (${done.length})</div>
    ${done.map(q=>`<div style="display:flex;justify-content:space-between;padding:.3rem 0;border-bottom:1px solid rgba(255,255,255,.04);font-size:.78rem;opacity:.5"><span>#${q.number} ${q.name} — ${q.service}</span><span>${new Date(q.doneAt||q.createdAt).toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit'})}</span></div>`).join('')}
  </div>`:''}`;
}

function openAddQueue(){
  const svcs=(DB.get('services')||[]).filter(s=>s.active);
  openModal(`<h3>📋 Tambah Antrian</h3>
    <div class="field"><label>Nama Customer</label><input class="finp" id="q-name" placeholder="Nama"></div>
    <div class="field"><label>Layanan</label><select class="finp" id="q-svc">${svcs.map(s=>`<option value="${s.name}">${s.name}</option>`).join('')}</select></div>
    <div class="modal-footer">
      <button class="btn btn-outline" onclick="closeModal()">Batal</button>
      <button class="btn btn-teal" onclick="saveQueue()">Tambah</button>
    </div>`);
}

function saveQueue(){
  const name=document.getElementById('q-name')?.value?.trim();
  const svc=document.getElementById('q-svc')?.value;
  if(!name){alert('Nama wajib diisi');return;}
  const queue=DB.get('queue')||[];
  const todayQueue=queue.filter(q=>new Date(q.createdAt).toDateString()===new Date().toDateString());
  const nextNum=(todayQueue.length>0?Math.max(...todayQueue.map(q=>q.number||0)):0)+1;
  queue.push({id:'q-'+Date.now(),name,service:svc,number:nextNum,status:'waiting',barber:'',createdAt:new Date().toISOString()});
  DB.set('queue',queue);
  closeModal();
  renderAntrian(document.getElementById('panel-antrian'));
}

function queueServe(id){
  const queue=DB.get('queue')||[];
  const q=queue.find(x=>x.id===id);
  if(q) q.status='serving';
  DB.set('queue',queue);
  renderAntrian(document.getElementById('panel-antrian'));
}

function queueDone(id){
  const queue=DB.get('queue')||[];
  const q=queue.find(x=>x.id===id);
  if(q){q.status='done';q.doneAt=new Date().toISOString();}
  DB.set('queue',queue);
  renderAntrian(document.getElementById('panel-antrian'));
}

function queueCancel(id){
  if(!confirm('Hapus dari antrian?')) return;
  DB.set('queue',(DB.get('queue')||[]).filter(q=>q.id!==id));
  renderAntrian(document.getElementById('panel-antrian'));
}

