function renderKasir(el){
  const svcs=(DB.get('services')||[]).filter(s=>s.active);
  const users=DB.get('users')||[];
  const barbers=users;
  el.innerHTML=`
  <div class="card">
    <div class="card-title">Pilih Layanan</div>
    <div class="service-grid" id="svcGrid"></div>
  </div>
  <div class="card">
    <div class="card-title">Add-ons & Produk</div>
    <div class="service-grid" id="addonGrid"></div>
  </div>
  <div class="card">
    <div class="card-title">Detail Transaksi
      <button class="btn btn-outline btn-sm" onclick="clearCart()">Bersihkan</button>
    </div>
    <div class="field">
      <label>Nama Customer</label>
      <input class="finp" id="custName" placeholder="Nama customer (opsional)">
    </div>
    <div class="field">
      <label>Barber</label>
      <select class="finp" id="barberSel">
        ${barbers.map(b=>`<option value="${b.id}">${b.name}</option>`).join('')}
      </select>
    </div>
    <div id="cartList"></div>
    <div class="cart-total" id="cartTotal">Total: Rp 0</div>
    <button class="btn btn-teal btn-full" onclick="checkout()" style="margin-top:.3rem">💳 Bayar & Cetak Struk</button>
  </div>`;
  cart=[];
  selectedPayMethod=null;
  renderSvcGrid();
  renderAddonGrid();
  renderCart();
}

function renderSvcGrid(){
  const svcs=(DB.get('services')||[]).filter(s=>s.active);
  const grid=document.getElementById('svcGrid');
  if(!grid) return;
  grid.innerHTML='';
  svcs.forEach(s=>{
    const qty=cart.filter(c=>c.id===s.id).length;
    const btn=document.createElement('div');
    btn.className='svc-btn'+(qty>0?' sel':'');
    btn.innerHTML=(qty>0?`<div class="svc-qty">${qty}</div>`:'')+
      `<div class="svc-name">${s.name}</div><div class="svc-price">${rp(s.price)}</div>`;
    btn.onclick=()=>{ cart.push({id:s.id,name:s.name,price:s.price}); renderSvcGrid(); renderCart(); };
    grid.appendChild(btn);
  });
}

function renderAddonGrid(){
  const addons=(DB.get('addons')||[]).filter(a=>a.active);
  const grid=document.getElementById('addonGrid');
  if(!grid) return;
  grid.innerHTML='';
  if(addons.length===0){
    grid.innerHTML='<div style="color:var(--ash);font-size:.75rem;padding:.3rem">Belum ada produk add-on</div>';
    return;
  }
  addons.forEach(a=>{
    const qty=cart.filter(c=>c.id==='ao-'+a.id).length;
    const inCartNow=cart.filter(c=>c.addonId===a.id).length;
    const stockLimit=a.stock!=null?a.stock:999;
    const outOfStock=(a.stock!==undefined&&a.stock<=0)||(inCartNow>=stockLimit&&stockLimit<999);
    const btn=document.createElement('div');
    btn.className='svc-btn'+(qty>0?' sel':'')+(outOfStock?' disabled':'');
    btn.style.opacity=outOfStock?'0.4':'1';
    const stockColor = outOfStock ? '#fca5a5' : '#52526e';
    const stockVal = a.stock != null ? a.stock : '~';
    btn.innerHTML = (qty > 0 ? '<div class="svc-qty">'+qty+'</div>' : '') +
      '<div class="svc-name">'+a.name+'</div>' +
      '<div class="svc-price">'+rp(a.price)+'</div>' +
      '<div style="font-size:.6rem;color:'+stockColor+';margin-top:2px">Stok: '+(stockLimit<999?Math.max(0,stockLimit-inCartNow)+'/'+stockLimit:stockVal)+'</div>';
    if(!outOfStock){
      btn.onclick=()=>{
        // Count how many of this addon already in cart
        const inCart=cart.filter(c=>c.addonId===a.id).length;
        const stock=a.stock!=null?a.stock:999;
        if(inCart>=stock){
          // Flash the button red briefly
          btn.style.borderColor='var(--ember)';
          btn.style.background='rgba(239,68,68,.12)';
          setTimeout(()=>{ btn.style.borderColor=''; btn.style.background=''; },800);
          return;
        }
        cart.push({id:'ao-'+a.id+'-'+Date.now(),name:a.name,price:a.price,isAddon:true,addonId:a.id});
        renderAddonGrid(); renderCart(); // re-render so button greyed if now at stock limit
      };
    }
    grid.appendChild(btn);
  });
}

function renderCart(){
  const list=document.getElementById('cartList');
  const totalEl=document.getElementById('cartTotal');
  if(!list) return;
  list.innerHTML='';
  const grouped={};
  cart.forEach(c=>{ grouped[c.id]=grouped[c.id]||{...c,qty:0}; grouped[c.id].qty++; });
  Object.values(grouped).forEach(c=>{
    const d=document.createElement('div');
    d.className='cart-item';
    const left=document.createElement('span');
    left.textContent=c.name+' x'+c.qty;
    const right=document.createElement('div');
    right.style.cssText='display:flex;align-items:center;gap:.5rem';
    const price=document.createElement('span');
    price.style.color='var(--teal)';
    price.textContent=rp(c.price*c.qty);
    const btn=document.createElement('button');
    btn.style.cssText='background:none;border:none;color:var(--ember);cursor:pointer;font-size:.9rem';
    btn.textContent='✕';
    btn.onclick=()=>{ removeFromCart(c.id); };
    right.appendChild(price); right.appendChild(btn);
    d.appendChild(left); d.appendChild(right);
    list.appendChild(d);
  });
  const total=cart.reduce((a,c)=>a+c.price,0);
  if(totalEl) totalEl.textContent='Total: '+rp(total);
}

function removeFromCart(id){
  const idx=cart.findLastIndex(c=>c.id===id);
  if(idx>=0) cart.splice(idx,1);
  renderSvcGrid(); renderCart();
}
function clearCart(){ cart=[]; renderSvcGrid(); renderCart(); }

function checkout(){
  if(cart.length===0){ alert('Pilih layanan dulu!'); return; }
  const name=document.getElementById('custName')?.value?.trim()||'Pelanggan';
  const barberId=document.getElementById('barberSel')?.value;
  const total=cart.reduce((a,c)=>a+c.price,0);
  // Show payment method modal using DOM
  const box = document.getElementById('modalBox');
  const methods = [
    {id:'cash', icon:'\u{1F4B5}', label:'Cash', color:''},
    {id:'tf',   icon:'\u{1F3E6}', label:'Transfer', color:''},
    {id:'qris', icon:'\u{1F4F1}', label:'QRIS', color:''},
    {id:'hutang',icon:'\u{1F4D2}',label:'Hutang', color:'var(--ember)'}
  ];
  box.innerHTML = '';
  const h3 = document.createElement('h3');
  h3.textContent = 'Metode Pembayaran';
  box.appendChild(h3);
  const sub = document.createElement('div');
  sub.style.cssText = 'font-size:.85rem;color:var(--ash);margin-bottom:1rem';
  sub.innerHTML = 'Total: <strong style="color:var(--teal);font-size:1.1rem">'+rp(total)+'</strong>';
  box.appendChild(sub);
  const grid = document.createElement('div');
  grid.style.cssText = 'display:grid;grid-template-columns:1fr 1fr;gap:.5rem;margin-bottom:1rem';
  methods.forEach(function(m){
    const btn = document.createElement('button');
    btn.className = 'pay-btn';
    btn.id = 'pay-'+m.id;
    if(m.color) btn.style.color = m.color;
    btn.innerHTML = '<div style="font-size:1.3rem">'+m.icon+'</div><div>'+m.label+'</div>';
    btn.onclick = function(){ selectPay(m.id); };
    grid.appendChild(btn);
  });
  box.appendChild(grid);
  const noteDiv = document.createElement('div');
  noteDiv.id = 'hutang-note';
  noteDiv.style.display = 'none';
  noteDiv.innerHTML = '<div class="field"><label>Catatan Hutang (opsional)</label><input class="finp" id="debt-note" placeholder="Bayar Jumat depan"></div>';
  box.appendChild(noteDiv);
  const footer = document.createElement('div');
  footer.className = 'modal-footer';
  const cancelBtn = document.createElement('button');
  cancelBtn.className = 'btn btn-outline';
  cancelBtn.textContent = 'Batal';
  cancelBtn.onclick = closeModal;
  const confirmBtn = document.createElement('button');
  confirmBtn.className = 'btn btn-teal';
  confirmBtn.id = 'confirmPayBtn';
  confirmBtn.textContent = 'Konfirmasi';
  confirmBtn.disabled = true;
  confirmBtn.onclick = confirmCheckout;
  footer.appendChild(cancelBtn);
  footer.appendChild(confirmBtn);
  box.appendChild(footer);
  document.getElementById('modalOverlay').classList.add('open');
}

let selectedPayMethod = null;
let discountMode = 'none'; // 'none' | 'pct' | 'rp'
let discountVal = 0;       // percentage or rp amount
let discountType = 'pct';  // for custom: 'pct' or 'rp'
let rewardClaimed = false;

function setDisc(mode, val){
  // Reset all chips
  ['dc-none','dc-10','dc-20','dc-50','dc-custom'].forEach(id=>{
    const el=document.getElementById(id);
    if(el) el.classList.remove('on');
  });
  const customInp=document.getElementById('discCustomInput');
  const preview=document.getElementById('discPreview');
  if(mode==='none'){
    discountMode='none'; discountVal=0;
    document.getElementById('dc-none')?.classList.add('on');
    if(customInp) customInp.style.display='none';
    if(preview) preview.style.display='none';
  } else if(mode==='pct'){
    discountMode='pct'; discountVal=val;
    document.getElementById('dc-'+val)?.classList.add('on');
    if(customInp) customInp.style.display='none';
    updateDiscPreview();
  } else if(mode==='custom'){
    discountMode='custom'; discountVal=0;
    document.getElementById('dc-custom')?.classList.add('on');
    if(customInp) customInp.style.display='flex';
    const v=document.getElementById('discCustomVal');
    if(v) v.value='';
  }
  renderCart();
}

function setDiscType(type){
  discountType=type;
  ['dc-type-pct','dc-type-rp'].forEach(id=>document.getElementById(id)?.classList.remove('on'));
  document.getElementById('dc-type-'+type)?.classList.add('on');
  calcDisc();
}

function calcDisc(){
  const v=parseInt(document.getElementById('discCustomVal')?.value)||0;
  discountVal=v;
  updateDiscPreview();
  renderCart();
}

function getDiscountAmount(subtotal){
  if(discountMode==='none') return 0;
  if(rewardClaimed) return 0; // reward handles its own discount
  if(discountMode==='pct') return Math.round(subtotal*(discountVal/100));
  if(discountMode==='custom'){
    if(discountType==='pct') return Math.round(subtotal*(discountVal/100));

[1536 more lines in file. Use offset=901 to continue.]

    return Math.min(discountVal, subtotal);
  }
  return 0;
}

function updateDiscPreview(){
  const preview=document.getElementById('discPreview');
  if(!preview) return;
  const subtotal=cart.reduce((a,c)=>a+c.price,0);
  const disc=getDiscountAmount(subtotal);
  if(disc>0){
    preview.style.display='block';
    preview.textContent='Diskon: -'+rp(disc)+' → Total: '+rp(subtotal-disc);
  } else preview.style.display='none';
}

function claimReward(){
  const custName=document.getElementById('custName')?.value?.trim();
  if(!custName) return;
  const members=DB.get('members')||[];
  const m=members.find(x=>x.name.toLowerCase()===custName.toLowerCase());
  if(!m) return;
  const settings=DB.get('settings')||{memberVisits:10};
  const target=settings.memberVisits||10;
  const cycleProgress=(m.visits||0)%target;
  if(cycleProgress!==0&&(m.visits||0)<target) return;
  rewardClaimed=true;
  // Visual feedback
  const btn=document.querySelector('#rewardAlert button');
  if(btn){btn.textContent='✅ Diklaim!';btn.disabled=true;}
  renderCart();
}

function resetPromo(){
  discountMode='none'; discountVal=0; discountType='pct'; rewardClaimed=false;
  setDisc('none',0);
}
function selectPay(method){
  selectedPayMethod=method;
  document.querySelectorAll('.pay-btn').forEach(b=>b.classList.remove('pay-sel'));
  document.getElementById('pay-'+method)?.classList.add('pay-sel');
  document.getElementById('confirmPayBtn').disabled=false;
  document.getElementById('hutang-note').style.display=method==='hutang'?'block':'none';
}

function confirmCheckout(){
  if(!selectedPayMethod) return;
  const name=document.getElementById('custName')?.value?.trim()||'Pelanggan';
  const barberId=document.getElementById('barberSel')?.value;
  const barbers=DB.get('users')||[];
  const barber=barbers.find(b=>b.id===barberId)||{name:barberId};
  const settings=DB.get('settings')||{commission:40};
  const total=cart.reduce((a,c)=>a+c.price,0);
  const isHutang=selectedPayMethod==='hutang';
  const commission=isHutang?0:Math.round(total*settings.commission/100);
  const debtNote=document.getElementById('debt-note')?.value?.trim()||'';
  const tx={
    id:'tx-'+Date.now(),
    date:new Date().toISOString(),
    customer:name,
    barber:barber.name,
    barberId,
    items:[...cart],
    total,
    commission,
    payMethod:selectedPayMethod,
    isHutang
  };
  // Save transaction (hutang = 0 commission, mark as unpaid)
  const txs=DB.get('transactions')||[];
  txs.push(tx);
  DB.set('transactions',txs);
  // If hutang — create debt record
  if(isHutang){
    const debts=DB.get('debts')||[];
    debts.push({
      id:'debt-'+Date.now(),
      txId:tx.id,
      customer:name,
      barber:barber.name,
      amount:total,
      note:debtNote,
      date:new Date().toISOString(),
      paid:false,
      paidAt:null
    });
    DB.set('debts',debts);
  }
  // Deduct addon stock
  const addons=DB.get('addons')||[];
  cart.filter(c=>c.isAddon).forEach(c=>{
    const a=addons.find(x=>x.id===c.addonId);
    if(a&&a.stock>0) a.stock--;
  });
  DB.set('addons',addons);
  updateMemberVisit(name);
  closeModal();
  printStruk(tx);
  // Full re-render kasir to ensure clean state
  cart=[];
  selectedPayMethod=null;
  resetPromo();
