function renderCal(){
  const days=['Min','Sen','Sel','Rab','Kam','Jum','Sab'];
  const year=calDate.getFullYear(), month=calDate.getMonth();
  const firstDay=new Date(year,month,1).getDay();
  const daysInMonth=new Date(year,month+1,0).getDate();
  const monthNames=['Januari','Februari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember'];
  document.getElementById('calMonthLabel').textContent=monthNames[month]+' '+year;
  const appts=DB.get('appointments')||[];
  const grid=document.getElementById('calGrid');
  if(!grid) return;
  // Day labels
  grid.innerHTML='<div class="cal-days">'+days.map(d=>`<div class="cal-day-lbl">${d}</div>`).join('')+'</div>';
  const daysDiv=document.createElement('div');
  daysDiv.className='cal-days';
  // Empty cells
  for(let i=0;i<firstDay;i++){
    const e=document.createElement('div');e.className='cal-day empty';daysDiv.appendChild(e);
  }
  const today=new Date();
  for(let d=1;d<=daysInMonth;d++){
    const dateStr=`${year}-${String(month+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
    const hasAppt=appts.some(a=>a.date===dateStr);
    const isToday=today.getDate()===d&&today.getMonth()===month&&today.getFullYear()===year;
    const div=document.createElement('div');
    div.className='cal-day'+(isToday?' today':'')+(hasAppt?' has-appt':'');
    div.textContent=d;
    div.onclick=()=>{ renderApptList(new Date(year,month,d)); };
    daysDiv.appendChild(div);
  }
  grid.appendChild(daysDiv);
}
function calPrev(){ calDate.setMonth(calDate.getMonth()-1); renderCal(); }
function calNext(){ calDate.setMonth(calDate.getMonth()+1); renderCal(); }

function renderApptList(date){
  const dateStr=`${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,'0')}-${String(date.getDate()).padStart(2,'0')}`;
  const appts=(DB.get('appointments')||[]).filter(a=>a.date===dateStr).sort((a,b)=>a.time.localeCompare(b.time));
  const el=document.getElementById('apptList');
  const lbl=document.getElementById('todayLabel');
  if(lbl) lbl.textContent=date.toLocaleDateString('id-ID',{day:'numeric',month:'short'});
  if(!el) return;
  if(appts.length===0){el.innerHTML='<div class="empty-state"><div class="ei">📅</div><p>Belum ada janji hari ini</p></div>';return;}
  el.innerHTML='';
  appts.forEach(a=>{
    const d=document.createElement('div');d.className='appt-slot';
    d.innerHTML=`<div class="appt-time">${a.time}</div>
    <div class="appt-info"><div class="appt-name">${a.customer}</div>
    <div class="appt-detail">${a.barber} · ${a.service}${a.phone?' · 📱'+a.phone:''}</div></div>
    <span class="badge badge-${a.status==='done'?'teal':a.status==='cancel'?'red':'gold'}">${a.status==='done'?'Selesai':a.status==='cancel'?'Batal':'Menunggu'}</span>
    ${a.phone?`<a href="${waLink(a.phone,'Halo '+a.customer+'! Pengingat: jadwal potong kamu di '+getShopName()+' hari ini jam '+a.time+'. Ditunggu ya! 💈')}" target="_blank" style="background:none;border:1px solid rgba(37,211,102,.3);border-radius:6px;color:#25D366;padding:.15rem .4rem;font-size:.68rem;text-decoration:none;white-space:nowrap">📱 WA</a>`:''}
    <button onclick="deleteAppt('${a.id}')" style="background:none;border:none;color:var(--ember);cursor:pointer;margin-left:.3rem">🗑️</button>`;
    el.appendChild(d);
  });
}

