function renderLaporanContent(){
  const el=document.getElementById('laporanContent');
  if(!el) return;
  const txs=DB.get('transactions')||[];
  const now=new Date();
  const filtered=txs.filter(tx=>{
    const d=new Date(tx.date);
    if(reportPeriod==='today') return d.toDateString()===now.toDateString();
    if(reportPeriod==='week'){const w=new Date(now);w.setDate(w.getDate()-7);return d>=w;}
    if(reportPeriod==='month') return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear();
    return true;
  });
  // Exclude hutang (unpaid) from revenue — only count paid transactions
  const paidTx=filtered.filter(t=>!t.isHutang);
  const hutangTx=filtered.filter(t=>t.isHutang);
  const total=paidTx.reduce((a,t)=>a+t.total,0);
  const totalHutang=hutangTx.reduce((a,t)=>a+t.total,0);
  const totalComm=paidTx.reduce((a,t)=>a+t.commission,0);
  const barberMap={};
  paidTx.forEach(t=>{ barberMap[t.barber]=(barberMap[t.barber]||0)+t.commission; });
  // Expenses for same period
  const allExp=DB.get('expenses')||[];
  const filteredExp=allExp.filter(e=>{
    const d=new Date(e.date);
    if(reportPeriod==='today') return d.toDateString()===now.toDateString();
    if(reportPeriod==='week'){const w=new Date(now);w.setDate(w.getDate()-7);return d>=w;}
    if(reportPeriod==='month') return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear();
    return true;
  });
  const totalExp=filteredExp.reduce((a,e)=>a+e.amount,0);
  const net=total-totalComm;
  const profit=net-totalExp;
  el.innerHTML=''+
  '<div class="grid3" style="margin-bottom:.6rem">'+
    '<div class="stat-card"><div class="stat-val">'+filtered.length+'</div><div class="stat-lbl">Transaksi</div></div>'+
    '<div class="stat-card"><div class="stat-val rp-val">'+rp(total)+'</div><div class="stat-lbl">Pendapatan (Cash/TF/QRIS)</div></div>'+
    '<div class="stat-card"><div class="stat-val rp-val">'+rp(net)+'</div><div class="stat-lbl">Net (setelah komisi)</div></div>'+
  '</div>'+
  (totalHutang>0?
    '<div style="background:rgba(239,68,68,.08);border:1px solid rgba(239,68,68,.25);border-radius:12px;padding:.7rem .9rem;margin-bottom:.6rem;display:flex;align-items:center;justify-content:space-between">'+
      '<div><div style="font-size:.72rem;font-weight:700;color:#fca5a5">⚠️ Piutang Belum Lunas</div>'+
      '<div style="font-size:.72rem;color:var(--ash)">'+hutangTx.length+' transaksi belum dibayar</div></div>'+
      '<div style="font-size:1rem;font-weight:800;color:var(--ember)">'+rp(totalHutang)+'</div>'+
    '</div>':'')+
  '<div class="grid3" style="margin-bottom:.6rem">'+
    '<div class="stat-card"><div class="stat-val rp-val" style="color:var(--ember)">'+rp(totalExp)+'</div><div class="stat-lbl">Total Belanja</div></div>'+
    '<div class="stat-card"><div class="stat-val rp-val" style="color:'+(profit>=0?'var(--sage)':'var(--ember)')+'">'+rp(Math.abs(profit))+'</div><div class="stat-lbl">'+(profit>=0?'✅ Profit Bersih':'❌ Rugi')+'</div></div>'+
    '<div class="stat-card"><div class="stat-val">'+paidTx.length+'/'+filtered.length+'</div><div class="stat-lbl">Lunas / Total Tx</div></div>'+
  '</div>'+`
