function getFilteredTx(){
  const txs=DB.get('transactions')||[];
  const now=new Date();
  return txs.filter(tx=>{
    const d=new Date(tx.date);
    if(reportPeriod==='today') return d.toDateString()===now.toDateString();
    if(reportPeriod==='week'){const w=new Date(now);w.setDate(w.getDate()-7);return d>=w;}
    if(reportPeriod==='month') return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear();
    return true;
  });
}

function exportCSV(){
  const txs=getFilteredTx();
  if(txs.length===0){alert('Tidak ada data untuk diekspor pada periode ini');return;}
  const rows=[['No','Tanggal','Waktu','Customer','Barber','Layanan','Total (Rp)','Komisi (Rp)']];
  txs.forEach((t,i)=>{
    const d=new Date(t.date);
    const items=t.items.map(x=>x.name).join(' + ');
    rows.push([
      i+1,
      d.toLocaleDateString('id-ID'),
      d.toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit'}),
      t.customer,
      t.barber,
      items,
      t.total,
      t.commission
    ]);
  });
  // Summary row
  const totalSum=txs.reduce((a,t)=>a+t.total,0);
  const commSum=txs.reduce((a,t)=>a+t.commission,0);
  rows.push([]);
  rows.push(['','','','','','TOTAL',totalSum,commSum]);
  rows.push(['','','','','','NET (setelah komisi)',totalSum-commSum,'']);

  const csv=rows.map(r=>r.map(c=>{
    const s=String(c===undefined||c===null?'':c);
    return s.includes(',')||s.includes('"')||s.includes('\n')?'"'+s.replace(/"/g,'""')+'"':s;
  }).join(',')).join('\n');

  const period={today:'hari-ini',week:'minggu-ini',month:'bulan-ini',all:'semua'}[reportPeriod];
  const fname='romebois-laporan-'+period+'-'+new Date().toISOString().split('T')[0]+'.csv';
  downloadFile(csv,'text/csv;charset=utf-8;',fname);
}

function exportJSON(){
