  const backup={
    version:1,
    exportedAt:new Date().toISOString(),
    exportedBy:currentUser.name,
    data:{
      transactions:       DB.get('transactions')||[],
      appointments:       DB.get('appointments')||[],
      members:            DB.get('members')||[],
      services:           DB.get('services')||[],
      settings:           DB.get('settings')||{},
      expenses:           DB.get('expenses')||[],
      expense_categories: DB.get('expense_categories')||[],
      addons:             DB.get('addons')||[],
      debts:              DB.get('debts')||[]
    }
  };
  const json=JSON.stringify(backup,null,2);
  downloadFile(json,'application/json','romebois-backup-'+now+'.json');
}

function importJSON(event){
  const file=event.target.files[0];
  if(!file) return;
  const reader=new FileReader();
  reader.onload=e=>{
    try{
      const backup=JSON.parse(e.target.result);
      if(!backup.version||!backup.data) throw new Error('Format file tidak valid');
      const d=backup.data;
      const confirm_msg=
        'Import backup dari '+new Date(backup.exportedAt).toLocaleString('id-ID')+'?\n\n'+
        '⚠️ Data yang ada akan DIGABUNG (bukan dihapus).\n'+
        'Transaksi duplikat akan dilewati.\n\n'+
        'Lanjutkan?';
      if(!confirm(confirm_msg)){event.target.value='';return;}

      let imported=0;
      // Merge transactions (by id)
      if(d.transactions){
        const existing=DB.get('transactions')||[];
        const existIds=new Set(existing.map(x=>x.id));
        const newTx=d.transactions.filter(x=>!existIds.has(x.id));
        DB.set('transactions',[...existing,...newTx]);
        imported+=newTx.length;
      }
      // Merge expenses
      if(d.expenses){
        const existing=DB.get('expenses')||[];
        const existIds=new Set(existing.map(x=>x.id));
        const newEx=d.expenses.filter(x=>!existIds.has(x.id));
        DB.set('expenses',[...existing,...newEx]);
      }
      if(d.expense_categories){
        const existing=DB.get('expense_categories')||[];
        const merged=[...new Set([...existing,...d.expense_categories])];
        DB.set('expense_categories',merged);
      }
      if(d.addons&&confirm('Timpa daftar add-ons & stok dengan data dari backup?')){
        DB.set('addons',d.addons);
      }
      if(d.debts){
        const existing=DB.get('debts')||[];
        const existIds=new Set(existing.map(x=>x.id));
        const newDb=d.debts.filter(x=>!existIds.has(x.id));
        DB.set('debts',[...existing,...newDb]);
      }
      // Merge appointments
      if(d.appointments){
        const existing=DB.get('appointments')||[];
        const existIds=new Set(existing.map(x=>x.id));
        const newAp=d.appointments.filter(x=>!existIds.has(x.id));
        DB.set('appointments',[...existing,...newAp]);
      }
      // Merge members
      if(d.members){
        const existing=DB.get('members')||[];
        const existIds=new Set(existing.map(x=>x.id));
        const newMb=d.members.filter(x=>!existIds.has(x.id));
        DB.set('members',[...existing,...newMb]);
      }
      // Overwrite services & settings only if admin confirms
      if(d.services&&confirm('Timpa daftar layanan & harga dengan data dari backup?')){
        DB.set('services',d.services);
      }
      if(d.settings&&confirm('Timpa pengaturan (komisi, member) dengan data dari backup?')){
        DB.set('settings',d.settings);
      }
      alert('✅ Import berhasil! '+imported+' transaksi baru ditambahkan.');
      renderPanel('laporan');
    } catch(err){
      alert('❌ Gagal import: '+err.message);
    }
    event.target.value='';
  };
  reader.readAsText(file);
}

function downloadFile(content, mimeType, filename){
  const blob=new Blob([content],{type:mimeType});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url; a.download=filename;
  document.body.appendChild(a); a.click();
  setTimeout(()=>{document.body.removeChild(a);URL.revokeObjectURL(url);},100);
}

function clearTx(){
  if(!confirm('Hapus SEMUA riwayat transaksi? Ini tidak bisa dibatalkan!')) return;
  DB.set('transactions',[]);
  renderLaporan(document.getElementById('panel-laporan'));
}

