function openAddAddon(){
  openModal(`<h3>🧴 Tambah Produk Add-on</h3>
    <div class="field"><label>Nama Produk</label><input class="finp" id="ao-name" placeholder="contoh: Pomade Gatsby"></div>
    <div class="field"><label>Harga Jual (Rp)</label><input class="finp" type="number" id="ao-price" placeholder="45000"></div>
    <div class="field"><label>Stok Awal</label><input class="finp" type="number" id="ao-stock" placeholder="10" value="0"></div>
    <div class="modal-footer">
      <button class="btn btn-outline" onclick="closeModal()">Batal</button>
      <button class="btn btn-teal" onclick="saveAddon(null)">Simpan</button>
    </div>`);
}

function openEditAddon(id){
  const addons=DB.get('addons')||[];
  const a=addons.find(x=>x.id===id);
  if(!a) return;
  openModal(`<h3>🧴 Edit Produk</h3>
    <div class="field"><label>Nama Produk</label><input class="finp" id="ao-name" value="${a.name}"></div>
    <div class="field"><label>Harga Jual (Rp)</label><input class="finp" type="number" id="ao-price" value="${a.price}"></div>
    <div class="field"><label>Stok</label><input class="finp" type="number" id="ao-stock" value="${a.stock||0}"></div>
    <div class="field"><label>Status</label><select class="finp" id="ao-active"><option value="true" ${a.active?'selected':''}>Aktif</option><option value="false" ${!a.active?'selected':''}>Nonaktif</option></select></div>
    <div class="modal-footer">
      <button class="btn btn-danger btn-sm" onclick="deleteAddon('${id}')">Hapus</button>
      <button class="btn btn-outline" onclick="closeModal()">Batal</button>
      <button class="btn btn-teal" onclick="saveAddon('${id}')">Simpan</button>
    </div>`);
}

function saveAddon(id){
  const name=document.getElementById('ao-name')?.value?.trim();
  const price=parseInt(document.getElementById('ao-price')?.value)||0;
  const stock=parseInt(document.getElementById('ao-stock')?.value)||0;
  const active=document.getElementById('ao-active')?.value!=='false';
  if(!name||!price){alert('Nama dan harga wajib diisi');return;}
  const addons=DB.get('addons')||[];
  if(id){
    const a=addons.find(x=>x.id===id);
    if(a){a.name=name;a.price=price;a.stock=stock;a.active=active;}
  } else {
    addons.push({id:'a-'+Date.now(),name,price,stock,active:true});
  }
  DB.set('addons',addons);
  closeModal();
  renderAdmin(document.getElementById('panel-admin'));
}

function deleteAddon(id){
  if(!confirm('Hapus produk ini?')) return;
  DB.set('addons',(DB.get('addons')||[]).filter(a=>a.id!==id));
  closeModal();
  renderAdmin(document.getElementById('panel-admin'));
}

function adjStock(id, delta){
  const addons=DB.get('addons')||[];
  const a=addons.find(x=>x.id===id);
  if(a){ a.stock=Math.max(0,(a.stock||0)+delta); DB.set('addons',addons); }
  renderAdmin(document.getElementById('panel-admin'));
}

